mapper.sql:
where nr.tenant_id = #{tenantId}
  and nr.del_flag = 0

  and nr.notify_status = #{statusCode}


  and (
    nr.notification_no like concat('%', #{keyword}, '%')
    or nr.related_order_no like concat('%', #{keyword}, '%')
    or nr.notification_type like concat('%', #{keyword}, '%')
    or nr.notify_status like concat('%', #{keyword}, '%')
    or nr.target_url like concat('%', #{keyword}, '%')
  )

mapper.select:

from payment_notification_record nr

order by nr.created_at desc
limit #{limit} offset #{offset}


from payment_notification_record nr
where nr.tenant_id = #{tenantId}
  and nr.id = #{id}
  and nr.del_flag = 0
limit 1

mapper.update:
update payment_notification_record
set notify_status = #{notifyStatus},
    response_code = #{responseCode},
    response_message = #{responseMessage},
    next_retry_time = #{nextRetryTime},
    updated_by = #{operatorId},
    updated_at = #{now}
where tenant_id = #{tenantId}
  and id = #{id}
  and del_flag = 0
